  const uint32_t maxNumAffineMergeCand = slice.getPicHeader()->getMaxNumAffineMergeCand();
  const unsigned plevel = pu.cs->sps->getLog2ParallelMergeLevelMinus2() + 2;

  // 初始化Affine Merge候选列表
  for ( int i = 0; i < maxNumAffineMergeCand; i++ )
